string_has_chars(<<>>) -> false;
string_has_chars([]) -> false.


decode_msg(Bin, MsgName) when is_binary(Bin) -> decode_msg(Bin, MsgName, []).

decode_msg(Bin, MsgName, Opts) when is_binary(Bin) ->
    TrUserData = proplists:get_value(user_data, Opts),
    decode_msg_1_catch(Bin, MsgName, TrUserData).

-ifdef('OTP_RELEASE').
decode_msg_1_catch(Bin, MsgName, TrUserData) ->
    try decode_msg_2_doit(MsgName, Bin, TrUserData)
    catch
        error:{gpb_error,_}=Reason:StackTrace ->
            erlang:raise(error, Reason, StackTrace);
        Class:Reason:StackTrace -> error({gpb_error,{decoding_failure, {Bin, MsgName, {Class, Reason, StackTrace}}}})
    end.
-else.
decode_msg_1_catch(Bin, MsgName, TrUserData) ->
    try decode_msg_2_doit(MsgName, Bin, TrUserData)
    catch
        error:{gpb_error,_}=Reason ->
            erlang:raise(error, Reason,
                         erlang:get_stacktrace());
        Class:Reason ->
            StackTrace = erlang:get_stacktrace(),
            error({gpb_error,{decoding_failure, {Bin, MsgName, {Class, Reason, StackTrace}}}})
    end.
-endif.

decode_msg_2_doit('yuzu.common.v1.Platform', Bin, TrUserData) -> id('decode_msg_yuzu.common.v1.Platform'(Bin, TrUserData), TrUserData);
decode_msg_2_doit('yuzu.common.v1.PluginInfo', Bin, TrUserData) -> id('decode_msg_yuzu.common.v1.PluginInfo'(Bin, TrUserData), TrUserData);
decode_msg_2_doit('yuzu.common.v1.ErrorDetail', Bin, TrUserData) -> id('decode_msg_yuzu.common.v1.ErrorDetail'(Bin, TrUserData), TrUserData);
decode_msg_2_doit('yuzu.common.v1.Timestamp', Bin, TrUserData) -> id('decode_msg_yuzu.common.v1.Timestamp'(Bin, TrUserData), TrUserData);
decode_msg_2_doit('yuzu.common.v1.ScopeExpression', Bin, TrUserData) -> id('decode_msg_yuzu.common.v1.ScopeExpression'(Bin, TrUserData), TrUserData);
decode_msg_2_doit('yuzu.common.v1.ScopeCondition', Bin, TrUserData) -> id('decode_msg_yuzu.common.v1.ScopeCondition'(Bin, TrUserData), TrUserData);
decode_msg_2_doit('yuzu.common.v1.ScopeCombinator', Bin, TrUserData) -> id('decode_msg_yuzu.common.v1.ScopeCombinator'(Bin, TrUserData), TrUserData).



