'dfp_read_field_def_yuzu.common.v1.Platform'(<<10, Rest/binary>>, Z1, Z2, F, F@_1, F@_2, F@_3, TrUserData) -> 'd_field_yuzu.common.v1.Platform_os'(Rest, Z1, Z2, F, F@_1, F@_2, F@_3, TrUserData);
